&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;41&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;42&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;43&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;44&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;45&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs python&#34;&gt;&lt;span class=&#34;hljs-comment&#34;&gt;#!/usr/bin/env python&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;hljs-comment&#34;&gt;# -*- coding: utf-8 -*-&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;hljs-comment&#34;&gt;# @Date : 2019-03-18 13:02:32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;hljs-comment&#34;&gt;# @Author : KK (xxxxx@xxxxx.com)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;hljs-comment&#34;&gt;# @Link : http://default.com&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;hljs-comment&#34;&gt;# @Version : $Id$&lt;/span&gt;&lt;br&gt;&lt;br&gt;&lt;span class=&#34;hljs-comment&#34;&gt;# -*- coding: utf-8 -*-&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;import&lt;/span&gt; urllib.request &lt;br&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;from&lt;/span&gt; bs4 &lt;span class=&#34;hljs-keyword&#34;&gt;import&lt;/span&gt; BeautifulSoup&lt;br&gt;&lt;br&gt;&lt;span class=&#34;hljs-comment&#34;&gt;#get book&amp;#x27;s chapter&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;get_chapter&lt;/span&gt;(&lt;span class=&#34;hljs-params&#34;&gt;url&lt;/span&gt;):&lt;/span&gt;&lt;br&gt; html = urllib.request.urlopen(url) &lt;br&gt; content = html.read().decode(&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;utf8&amp;#x27;&lt;/span&gt;)&lt;br&gt; html.close()&lt;br&gt; soup = BeautifulSoup(content, &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;lxml&amp;quot;&lt;/span&gt;)&lt;br&gt; title = soup.find(&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;h1&amp;#x27;&lt;/span&gt;).text &lt;span class=&#34;hljs-comment&#34;&gt;#chapter title&lt;/span&gt;&lt;br&gt; text = soup.find(&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;div&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;hljs-built_in&#34;&gt;id&lt;/span&gt;=&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;htmlContent&amp;#x27;&lt;/span&gt;) &lt;span class=&#34;hljs-comment&#34;&gt;#chapter content&lt;/span&gt;&lt;br&gt; &lt;span class=&#34;hljs-comment&#34;&gt;#processing the content to get nice style&lt;/span&gt;&lt;br&gt; content = text.get_text(&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;
&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;br/&amp;#x27;&lt;/span&gt;).replace(&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;
&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;
 &amp;#x27;&lt;/span&gt;)&lt;br&gt; content = content.replace(&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27; &amp;#x27;&lt;/span&gt;, &lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;
 &amp;#x27;&lt;/span&gt;)&lt;br&gt; &lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; title, &lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27; &amp;#x27;&lt;/span&gt;+content&lt;br&gt;&lt;br&gt;&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;main&lt;/span&gt;():&lt;/span&gt;&lt;br&gt; books = [&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;射雕英雄传&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;天龙八部&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;鹿鼎记&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;神雕侠侣&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;笑傲江湖&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;碧血剑&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;倚天屠龙记&amp;#x27;&lt;/span&gt;,\&lt;br&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;飞狐外传&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;书剑恩仇录&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;连城诀&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;侠客行&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;越女剑&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;鸳鸯刀&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;白马啸西风&amp;#x27;&lt;/span&gt;,\&lt;br&gt; &lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;雪山飞狐&amp;#x27;&lt;/span&gt;]&lt;br&gt; order = [&lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;,&lt;span class=&#34;hljs-number&#34;&gt;2&lt;/span&gt;,&lt;span class=&#34;hljs-number&#34;&gt;3&lt;/span&gt;,&lt;span class=&#34;hljs-number&#34;&gt;4&lt;/span&gt;,&lt;span class=&#34;hljs-number&#34;&gt;5&lt;/span&gt;,&lt;span class=&#34;hljs-number&#34;&gt;6&lt;/span&gt;,&lt;span class=&#34;hljs-number&#34;&gt;7&lt;/span&gt;,&lt;span class=&#34;hljs-number&#34;&gt;8&lt;/span&gt;,&lt;span class=&#34;hljs-number&#34;&gt;10&lt;/span&gt;,&lt;span class=&#34;hljs-number&#34;&gt;11&lt;/span&gt;,&lt;span class=&#34;hljs-number&#34;&gt;12&lt;/span&gt;,&lt;span class=&#34;hljs-number&#34;&gt;14&lt;/span&gt;,&lt;span class=&#34;hljs-number&#34;&gt;15&lt;/span&gt;,&lt;span class=&#34;hljs-number&#34;&gt;13&lt;/span&gt;,&lt;span class=&#34;hljs-number&#34;&gt;9&lt;/span&gt;] &lt;span class=&#34;hljs-comment&#34;&gt;#order of books to scrapy&lt;/span&gt;&lt;br&gt; &lt;span class=&#34;hljs-comment&#34;&gt;#list to store each book&amp;#x27;s scrapying range&lt;/span&gt;&lt;br&gt; page_range = [&lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;,&lt;span class=&#34;hljs-number&#34;&gt;43&lt;/span&gt;,&lt;span class=&#34;hljs-number&#34;&gt;94&lt;/span&gt;,&lt;span class=&#34;hljs-number&#34;&gt;145&lt;/span&gt;,&lt;span class=&#34;hljs-number&#34;&gt;185&lt;/span&gt;,&lt;span class=&#34;hljs-number&#34;&gt;225&lt;/span&gt;,&lt;span class=&#34;hljs-number&#34;&gt;248&lt;/span&gt;,&lt;span class=&#34;hljs-number&#34;&gt;289&lt;/span&gt;,&lt;span class=&#34;hljs-number&#34;&gt;309&lt;/span&gt;,&lt;span class=&#34;hljs-number&#34;&gt;329&lt;/span&gt;,&lt;span class=&#34;hljs-number&#34;&gt;341&lt;/span&gt;,&lt;span class=&#34;hljs-number&#34;&gt;362&lt;/span&gt;,&lt;span class=&#34;hljs-number&#34;&gt;363&lt;/span&gt;,&lt;span class=&#34;hljs-number&#34;&gt;364&lt;/span&gt;,&lt;span class=&#34;hljs-number&#34;&gt;375&lt;/span&gt;,&lt;span class=&#34;hljs-number&#34;&gt;385&lt;/span&gt;]&lt;br&gt;&lt;br&gt; &lt;span class=&#34;hljs-keyword&#34;&gt;for&lt;/span&gt; i,book &lt;span class=&#34;hljs-keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;hljs-built_in&#34;&gt;enumerate&lt;/span&gt;(books):&lt;br&gt; &lt;span class=&#34;hljs-keyword&#34;&gt;for&lt;/span&gt; num &lt;span class=&#34;hljs-keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;hljs-built_in&#34;&gt;range&lt;/span&gt;(page_range[i],page_range[i+&lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;]):&lt;br&gt; url = &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;http://jinyong.zuopinj.com/%s/%s.html&amp;quot;&lt;/span&gt;%(order[i],num)&lt;br&gt; &lt;span class=&#34;hljs-keyword&#34;&gt;try&lt;/span&gt;:&lt;br&gt; title, chapter = get_chapter(url)&lt;br&gt; &lt;span class=&#34;hljs-keyword&#34;&gt;with&lt;/span&gt; &lt;span class=&#34;hljs-built_in&#34;&gt;open&lt;/span&gt;(&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;F://%s.txt&amp;#x27;&lt;/span&gt;%book, &lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;a&amp;#x27;&lt;/span&gt;, encoding=&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;gb18030&amp;#x27;&lt;/span&gt;) &lt;span class=&#34;hljs-keyword&#34;&gt;as&lt;/span&gt; f:&lt;br&gt; &lt;span class=&#34;hljs-built_in&#34;&gt;print&lt;/span&gt;(book+&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;:&amp;#x27;&lt;/span&gt;+title+&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;--&amp;gt;写入成功！&amp;#x27;&lt;/span&gt;)&lt;br&gt; f.write(title+&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;


&amp;#x27;&lt;/span&gt;)&lt;br&gt; f.write(chapter+&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;


&amp;#x27;&lt;/span&gt;)&lt;br&gt; &lt;span class=&#34;hljs-keyword&#34;&gt;except&lt;/span&gt; Exception &lt;span class=&#34;hljs-keyword&#34;&gt;as&lt;/span&gt; e:&lt;br&gt; &lt;span class=&#34;hljs-built_in&#34;&gt;print&lt;/span&gt;(e) &lt;br&gt; &lt;span class=&#34;hljs-built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;全部写入完毕!&amp;#x27;&lt;/span&gt;) &lt;br&gt;main()&lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
